class MinHeap {
    constructor(arr) {
        this.heap = [];
        if (arr) {
            this.heap = [...arr];
            this.buildHeap();
        }
    }

    buildHeap() {
        for (let i = Math.floor(this.heap.length / 2) - 1; i >= 0; i--) {
            this.sinkDown(i);
        }
    }

    push(val) {
        this.heap.push(val);
        this.bubbleUp(this.heap.length - 1);
    }

    pop() {
        if (this.heap.length === 0) return null;
        const top = this.heap[0];
        const last = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = last;
            this.sinkDown(0);
        }
        return top;
    }

    top() {
        return this.heap.length > 0 ? this.heap[0] : null;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    bubbleUp(idx) {
        const element = this.heap[idx];
        while (idx > 0) {
            const parentIdx = (idx - 1) >> 1;
            const parent = this.heap[parentIdx];
            if (element >= parent) break;
            this.heap[parentIdx] = element;
            this.heap[idx] = parent;
            idx = parentIdx;
        }
    }

    sinkDown(idx) {
        const size = this.heap.length;
        while (true) {
            const left = 2 * idx + 1;
            const right = 2 * idx + 2;
            let smallest = idx;
            if (left < size && this.heap[left] < this.heap[smallest]) {
                smallest = left;
            }
            if (right < size && this.heap[right] < this.heap[smallest]) {
                smallest = right;
            }
            if (smallest === idx) break;
            [this.heap[idx], this.heap[smallest]] = [this.heap[smallest], this.heap[idx]];
            idx = smallest;
        }
    }
}

function solve(c, connections, queries) {
    const parent = new Array(c);
    const rank = new Array(c).fill(0);
    for (let i = 0; i < c; i++) {
        parent[i] = i;
    }

    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x, y) {
        const rx = find(x);
        const ry = find(y);
        if (rx === ry) return;
        if (rank[rx] < rank[ry]) {
            parent[rx] = ry;
        } else if (rank[rx] > rank[ry]) {
            parent[ry] = rx;
        } else {
            parent[ry] = rx;
            rank[rx]++;
        }
    }

    for (const [u, v] of connections) {
        const uIdx = u - 1;
        const vIdx = v - 1;
        union(uIdx, vIdx);
    }

    const rootOf = new Array(c);
    for (let i = 0; i < c; i++) {
        rootOf[i] = find(i);
    }

    const groups = {};
    for (let i = 0; i < c; i++) {
        const r = rootOf[i];
        if (!groups[r]) {
            groups[r] = [];
        }
        groups[r].push(i + 1);
    }

    const heapMap = {};
    for (const rootKey in groups) {
        heapMap[rootKey] = new MinHeap(groups[rootKey]);
    }

    const online = new Array(c).fill(true);
    const result = [];

    for (const [type, x] of queries) {
        const nodeIdx = x - 1;
        if (type === 1) {
            if (online[nodeIdx]) {
                result.push(x);
            } else {
                const root = rootOf[nodeIdx];
                const heap = heapMap[root];
                if (!heap) {
                    result.push(-1);
                    continue;
                }
                let minOnline = -1;
                while (!heap.isEmpty()) {
                    const topNode = heap.top();
                    if (online[topNode - 1]) {
                        minOnline = topNode;
                        break;
                    } else {
                        heap.pop();
                    }
                }
                result.push(minOnline);
            }
        } else if (type === 2) {
            online[nodeIdx] = false;
        }
    }

    return result;
}
