function solve(c, connections, queries) {
    class MinHeap {
        constructor(arr) {
            this.arr = arr;
            this.size = arr.length;
            this.buildHeap();
        }

        buildHeap() {
            for (let i = Math.floor(this.size / 2) - 1; i >= 0; i--) {
                this.heapifyDown(i);
            }
        }

        heapifyDown(i) {
            while (true) {
                let smallest = i;
                let left = 2 * i + 1;
                let right = 2 * i + 2;
                if (left < this.size && this.arr[left] < this.arr[smallest]) {
                    smallest = left;
                }
                if (right < this.size && this.arr[right] < this.arr[smallest]) {
                    smallest = right;
                }
                if (smallest === i) {
                    break;
                }
                [this.arr[i], this.arr[smallest]] = [this.arr[smallest], this.arr[i]];
                i = smallest;
            }
        }

        pop() {
            if (this.size === 0) return;
            this.arr[0] = this.arr[this.size - 1];
            this.size--;
            if (this.size > 0) {
                this.heapifyDown(0);
            }
        }

        getMinOnline(online) {
            while (this.size > 0) {
                let topVal = this.arr[0];
                if (online[topVal]) {
                    return topVal;
                } else {
                    this.pop();
                }
            }
            return -1;
        }
    }

    const n = c;
    let online = new Array(n + 1).fill(true);
    let graph = new Array(n + 1);
    for (let i = 0; i <= n; i++) {
        graph[i] = [];
    }

    for (let conn of connections) {
        let [u, v] = conn;
        graph[u].push(v);
        graph[v].push(u);
    }

    let compRep = new Array(n + 1).fill(0);
    let visited = new Array(n + 1).fill(false);
    let heaps = new Array(n + 1).fill(null);

    for (let i = 1; i <= n; i++) {
        if (!visited[i]) {
            visited[i] = true;
            let queue = [i];
            let ptr = 0;
            let minNode = i;
            while (ptr < queue.length) {
                let u = queue[ptr];
                ptr++;
                for (let v of graph[u]) {
                    if (!visited[v]) {
                        visited[v] = true;
                        queue.push(v);
                        if (v < minNode) minNode = v;
                    }
                }
            }
            for (let node of queue) {
                compRep[node] = minNode;
            }
            heaps[minNode] = new MinHeap(queue);
        }
    }

    let res = [];
    for (let q of queries) {
        let type = q[0];
        let x = q[1];
        if (type === 1) {
            if (online[x]) {
                res.push(x);
            } else {
                let rep = compRep[x];
                let heap = heaps[rep];
                let minOnline = heap.getMinOnline(online);
                res.push(minOnline);
            }
        } else if (type === 2) {
            online[x] = false;
        }
    }

    return res;
}
